/**
 * List results for a job.
 * @summary List Job Results
 */
export const JobsListJobResultsParams = zod.object({
  workspace: zod.string(),
  name: zod.string(),
});

export const jobsListJobResultsQuerySortDefault = `-created_at`;

export const JobsListJobResultsQueryParams = zod.object({
  sort: zod
    .enum(['created_at', '-created_at', 'updated_at', '-updated_at'])
    .default(jobsListJobResultsQuerySortDefault)
    .describe(
      'The field to sort by. To sort in decreasing order, use `-` in front of the field name.'
    ),
});

export const JobsListJobResultsResponse = zod.object({
  data: zod.array(
    zod.object({
      name: zod.string(),
      job: zod.string(),
      workspace: zod.string(),
      project: zod.string().optional(),
      created_at: zod.string().datetime({}).optional(),
      updated_at: zod.string().datetime({}).optional(),
      artifact_url: zod.string(),
      artifact_storage_type: zod.enum(['fileset']),
      download_url: zod.string().optional(),
    })
  ),
});

